function getTransferHistoryClassChipStyle(className: string | null | undefined) {
  if (!className) {
    return undefined;
  }

  const palette = ["#ff8a80", "#b71c1c", "#a5d6a7", "#1b5e20", "#90caf9", "#0d47a1", "#ffe082", "#e65100"];
  const hash = Array.from(className).reduce((sum, char) => sum + char.charCodeAt(0), 0);
  const backgroundColor = palette[hash % palette.length] ?? "#90caf9";
  const darkBackgrounds = new Set(["#b71c1c", "#1b5e20", "#0d47a1", "#e65100"]);

  return {
    backgroundColor,
    color: darkBackgrounds.has(backgroundColor) ? "#ffffff" : "#151515",
  };
}

function getTeamLogoModel(team: Pick<Team, "teamId" | "name" | "logoPath">) {
  const src =
    [team.logoPath].find((value) => typeof value === "string" && value.length > 0 && !value.startsWith("/Users/")) ??
    (team.logoPath?.startsWith("/Users/") ? `/api/media/team-logo/${encodeURIComponent(team.teamId)}` : null);

  const initials = team.name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? "")
    .join("") || "?";

  return { src, initials };
}

function sortRows<T>(rows: T[], sortState: SortState | undefined, accessors: Record<string, (row: T) => string | number>) {
  if (!sortState) {
    return rows;
  }

  const accessor = accessors[sortState.key];
  if (!accessor) {
    return rows;
  }

  return [...rows].sort((left, right) => {
    const result = compareSortValues(accessor(left), accessor(right));
    return sortState.direction === "asc" ? result : -result;
  });
}

function SortableHeader({
  label,
  tableId,
  columnKey,
  sortState,
  onToggle,
}: {
  label: string;
  tableId: string;
  columnKey: string;
  sortState?: SortState;
  onToggle: (tableId: string, columnKey: string) => void;
}) {
  const isActive = sortState?.key === columnKey;
  const arrow = !isActive ? "↕" : sortState.direction === "asc" ? "↑" : "↓";

  return (
    <button
      className={`sortable-header${isActive ? " is-active" : ""}`}
      type="button"
      onClick={() => onToggle(tableId, columnKey)}
    >
      <span>{label}</span>
      <span className="sortable-arrow">{arrow}</span>
    </button>
  );
}

function ColumnVisibilityManager({
  title,
  columns,
  presets = [],
  activePreset = null,
  isVisible,
  onToggle,
  onMove,
  getWidth,
  onStepWidth,
  onResetWidth,
  onApplyPreset,
  onResetToDefault,
}: {
  title: string;
  columns: FoundationTableColumn[];
  presets?: FoundationTablePreset[];
  activePreset?: FoundationTablePresetId | null;
  isVisible: (columnId: string, visibleByDefault?: boolean) => boolean;
  onToggle: (columnId: string, nextVisible: boolean) => void;
  onMove?: (columnId: string, direction: "left" | "right") => void;
  getWidth?: (column: FoundationTableColumn) => number;
  onStepWidth?: (column: FoundationTableColumn, delta: number) => void;
  onResetWidth?: (column: FoundationTableColumn) => void;
  onApplyPreset?: (presetId: Exclude<FoundationTablePresetId, "custom">) => void;
  onResetToDefault?: () => void;
}) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className={`column-visibility-manager${isOpen ? " is-open" : ""}`}>
      <button
        className="column-visibility-toggle"
        type="button"
        title="Spalten, Breite & Reihenfolge"
        aria-expanded={isOpen}
        onClick={() => setIsOpen((current) => !current)}
      >
        <span>{title}</span>
        <span className="column-visibility-toggle-icon" aria-hidden="true">
          {isOpen ? "−" : "+"}
        </span>
      </button>
      {isOpen && presets.length > 0 ? (
        <div className="table-customization-presets">
          <label className="filter-field table-customization-preset-field">
            <span>Preset</span>
            <select
              className="input"
              value={activePreset && activePreset !== "custom" ? activePreset : "custom"}
              onChange={(event) => {
                if (event.target.value === "custom") {
                  return;
                }
                onApplyPreset?.(event.target.value as Exclude<FoundationTablePresetId, "custom">);
              }}
            >
              {presets.map((preset) => (
                <option key={preset.id} value={preset.id}>
                  {preset.label}
                </option>
              ))}
              <option value="custom">Custom</option>
            </select>
          </label>
          <button className="secondary-button inline-button" type="button" onClick={onResetToDefault}>
            Layout zurücksetzen
          </button>
        </div>
      ) : null}
      {isOpen ? (
        <div className="table-customization-presets">
          <button
            className="secondary-button inline-button"
            type="button"
            onClick={() => columns.forEach((column) => onToggle(column.id, true))}
          >
            Alle anzeigen
          </button>
          {presets.length === 0 && onResetToDefault ? (
            <button className="secondary-button inline-button" type="button" onClick={onResetToDefault}>
              Layout zurücksetzen
            </button>
          ) : null}
        </div>
      ) : null}
      {isOpen ? <div className="column-visibility-grid">
        {columns.map((column) => {
          const checked = isVisible(column.id, column.visibleByDefault);
          return (
            <div key={column.id} className="column-visibility-option">
              <div className="table-customization-option-main">
                <label className="table-customization-checkbox">
                  <input
                    type="checkbox"
                    checked={checked}
                    onChange={(event) => onToggle(column.id, event.target.checked)}
                  />
                  <span>{column.label}</span>
                </label>
              </div>
              <div className="table-customization-option-actions">
                {typeof getWidth === "function" ? <span className="table-customization-width">{getWidth(column)} px</span> : null}
                {onMove ? (
                  <>
                    <button className="ghost-button" type="button" onClick={() => onMove(column.id, "left")} aria-label={`${column.label} nach links`}>
                      ←
                    </button>
                    <button className="ghost-button" type="button" onClick={() => onMove(column.id, "right")} aria-label={`${column.label} nach rechts`}>
                      →
                    </button>
                  </>
                ) : null}
                {onStepWidth ? (
                  <>
                    <button className="ghost-button" type="button" onClick={() => onStepWidth(column, -16)} aria-label={`${column.label} schmaler`}>
                      −
                    </button>
                    <button className="ghost-button" type="button" onClick={() => onStepWidth(column, 16)} aria-label={`${column.label} breiter`}>
                      +
                    </button>
                  </>
                ) : null}
                {onResetWidth ? (
                  <button className="ghost-button" type="button" onClick={() => onResetWidth(column)} aria-label={`${column.label} Breite zurücksetzen`}>
                    Reset
                  </button>
                ) : null}
              </div>
            </div>
          );
        })}
      </div> : null}
    </div>
  );
}

function formatMoney(value: number) {
  return new Intl.NumberFormat("de-DE", {
    maximumFractionDigits: 0,
  }).format(value);
}

function formatNullableMoney(value: number | null | undefined) {
  return value == null ? "—" : formatMoney(value);
}

function formatDisplayMoney(value: number) {
  return new Intl.NumberFormat("de-DE", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

function formatShortSaveId(saveId: string) {
  return saveId.length <= 14 ? saveId : `${saveId.slice(0, 8)}…${saveId.slice(-5)}`;
}

function formatScenarioTypeLabel(scenarioType?: string | null) {
  switch (scenarioType) {
    case "fresh_start":
      return "Fresh Start";
    case "ai_redraft_test":
      return "Redraft Test";
    case "season1_simulation":
      return "S1 Simulation";
    case "season1_completed":
      return "S1 Completed";
    case "season_transition_test":
      return "Transition Test";
    case "season2_start":
      return "S2 Start";
    case "live_feature_test":
      return "Live Test";
    case "sandbox_multiseason_test":
      return "Sandbox";
    case "sandbox_snapshot":
      return "Sandbox Snapshot";
    default:
      return "Unmarkiert";
  }
}

function formatFeatureAuditStatus(status: FeatureAuditStatus) {
  if (status === "planned") return "Geplant";
  if (status === "preview") return "Preview";
  if (status === "local_write") return "Local Write";
  if (status === "sandbox_ready") return "Sandbox";
  if (status === "multiplayer_ready") return "Multiplayer";
  if (status === "prod_ready") return "Prod";
  return status;
}

function resolveScenarioMetaLabel(meta?: SaveSummary["scenarioMeta"] | null) {
  if (!meta) return "default/fresh";
  switch (meta.scenarioType) {
    case "ai_redraft_test":
      return "clean-redraft";
    case "season1_simulation":
      return "simulation";
    case "season1_completed":
      return "season-end";
    case "season_transition_test":
      return "transition-test";
    case "season2_start":
      return "season-2-start";
    case "live_feature_test":
      return "live-test";
    case "sandbox_multiseason_test":
      return "sandbox";
    case "sandbox_snapshot":
      return "sandbox-snapshot";
    case "fresh_start":
      return "default/fresh";
    default:
      return "planning";
  }
}

function buildScenarioWarning(meta?: SaveSummary["scenarioMeta"] | null) {
  if (!meta) return "Alte Save-Struktur ohne Scenario-Meta.";
  if (meta.scenarioType === "sandbox_multiseason_test") {
    return "Sandbox-Testsave: lokale Test-Writes erlaubt, nicht produktiv.";
  }
  if (meta.scenarioType === "sandbox_snapshot") {
    return "Sandbox-Snapshot: stabiler Ruecksprungpunkt, nicht aktiv beschreiben.";
  }
  if (meta.scenarioType === "ai_redraft_test" && !meta.containsFinalStandings) {
    return "Dieser Save ist ein Redraft-Testsave ohne abgeschlossene Season.";
  }
  if (!meta.containsFinalStandings && meta.scenarioType !== "fresh_start" && meta.scenarioType !== "season2_start") {
    return "Dieser Save enthält keine abgeschlossene Season.";
  }
  return null;
}

function buildContextStatusChips(meta?: SaveSummary["scenarioMeta"] | null) {
  return [
    {
      label: meta?.scenarioType === "sandbox_multiseason_test" ? "Sandbox" : "Kein Sandbox",
      ready: meta?.scenarioType === "sandbox_multiseason_test",
      warning: meta?.scenarioType === "sandbox_snapshot",
    },
    {
      label: meta?.allowTestWrites ? "Test Writes erlaubt" : "Test Writes aus",
      ready: Boolean(meta?.allowTestWrites),
      warning: Boolean(meta?.allowTestWrites),
    },
    {
      label: meta?.allowTestWrites ? "Nicht Produktiv" : "Produktivschutz",
      ready: !meta?.allowTestWrites,
      warning: Boolean(meta?.allowTestWrites),
    },
    {
      label: `S1 Ergebnisse ${meta?.containsSeasonHistory ? "vorhanden" : "fehlen"}`,
      ready: Boolean(meta?.containsSeasonHistory),
    },
    {
      label: `Final Standings ${meta?.containsFinalStandings ? "vorhanden" : "fehlen"}`,
      ready: Boolean(meta?.containsFinalStandings),
    },
    {
      label: `Season 2 ${meta?.activeSeasonId === "season-2" ? "aktiv" : "nicht aktiv"}`,
      ready: meta?.activeSeasonId === "season-2",
    },
    {
      label: meta?.scenarioType === "ai_redraft_test" ? "Redraft Testsave" : "Kein Redraft",
      ready: meta?.scenarioType !== "ai_redraft_test",
      warning: meta?.scenarioType === "ai_redraft_test",
    },
    {
      label: meta?.gamePhase ? `Phase ${meta.gamePhase}` : "Planning",
      ready: meta?.gamePhase !== "season_active",
    },
  ];
}

function buildViewContextWarning(
  view: FoundationView,
  meta: SaveSummary["scenarioMeta"] | null,
  gamePhase: string | null | undefined,
) {
  if (meta?.scenarioType === "sandbox_multiseason_test") {
    return "Sandbox-Testsave: lokale Test-Writes sind erlaubt; Prisma/Remote/Direktinserts bleiben verboten.";
  }
  if (meta?.scenarioType === "sandbox_snapshot") {
    return "Sandbox-Snapshot: stabiler Ruecksprungpunkt, bitte nicht als aktiven Schreibsave nutzen.";
  }

  if (meta?.scenarioType === "ai_redraft_test") {
    return "Redraft-Testsave: enthält Kader-/Pickdaten, aber keine vollständige Season-Historie.";
  }

  if ((view === "season" || view === "prize" || view === "cockpit") && !meta?.containsFinalStandings) {
    return "Dieser Save hat keine abgeschlossenen Season-Daten.";
  }

  if (
    view === "training" &&
    (gamePhase ?? "season_active") === "season_active" &&
    !meta?.containsFinalStandings
  ) {
    return "Season-End Workflow blockiert: Season ist nicht abgeschlossen.";
  }

  return null;
}

function getViewSourceBadgeLabel(view: FoundationView, meta?: SaveSummary["scenarioMeta"] | null) {
	  if (view === "home") return "source: manager home snapshot";
	  if (view === "inbox") return "source: derived inbox";
	  if (view === "season") return meta?.containsFinalStandings ? "source: local season results" : "source: active local save";
  if (view === "prize") return "source: season-end forecast";
  if (view === "market") return "source: active local save";
  if (view === "training") return "source: local roster/progression";
  if (view === "matchdayArena") return meta?.containsFinalStandings ? "source: resolved matchday" : "source: active matchday";
  if (view === "matchdayResult") return "source: local matchday results";
  if (view === "history") return "source: active local save";
  return "source: active local save";
}

